!(function () {
    tinymce.PluginManager.add('charcount', function (e) {
        function t() {
            var t = e.getContent({ format: 'text' }),
                n = 0;
            for (var r of t) /[\u0000-\u001F\u007F\uFFFD]/.test(r) || n++;
            var a = e.theme.panel && e.theme.panel.find('#statusbar')[0];
            if (a) {
                var o = e.theme.panel.find('#charcount');
                o && o.text('Characters: ' + n);
            }
        }
        e.on('init', function () {
            var n = e.theme.panel && e.theme.panel.find('#statusbar')[0];
            n &&
                setTimeout(function () {
                    n.insert({ type: 'label', name: 'charcount', text: 'Characters: 0', classes: 'charcount', disabled: e.settings.readonly }, 0),
                        t(),
                        e.on('setcontent beforeaddundo undo redo keyup change', function () {
                            setTimeout(t, 1e3);
                        });
                }, 0);
        });
    });
})();
